mapper.select:
SELECT SEQ_NO, LONGITUDE AS LON, LATITUDE AS LAT, STORAGE_YARD_GID AS STACK_CODE FROM M_STORAGE_YARD_COORDINATE WHERE STORAGE_YARD_GID IN
#{stackCode}
ORDER BY STACK_CODE, SEQ_NO

mapper.update:
UPDATE M_STORAGE_STACK_POSITION
SET DEL_FLAG = '1'
WHERE STACK_ID = #{stackId,jdbcType=BIGINT}


        #{id}

mapper.select:
SELECT T1.ID, T1.PORT_STORAGE_ID, T1.CARGO_INFO_ID, T1.WORK_DATE, T1.CLASS_CODE, T1.CLASS_NAME, T1.PROCESS_DETAIL_CODE, T1.PROCESS_DETAIL_NAME, T1.STOREHOUSE_ID, T1.STOREHOUSE_NAME, T1.REGION_ID, T1.REGION_NAME, T1.MASS_ID, T1.MASS_NAME, T1.QUANTITY, T1.TON, T1.INOUT_TYPE, T1.INOUT_STORAGE_CODE, T1.INOUT_STORAGE_NAME, T1.WORK_TICKET_ID, T1.WORK_TICKET_DETAIL_ID, T1.CARGO_TALLY_ID, T1.CARGO_TALLY_DETAIL_ID, T1.INOUT_DATE, T1.CREATE_BY, T1.CREATE_BY_NAME, T1.CREATE_TIME, T1.UPDATE_BY, T1.UPDATE_BY_NAME, T1.UPDATE_TIME, T1.COMPANY_ID, T1.COMPANY_NAME, T1.CLEAN_MASS_SIGN, T2.TRANSPORT_EQUIPMENT_NO, T2.CREATE_BY_NAME AS "TALLY_MAN", T2.CREATE_TIME AS "TALLY_TIME"
FROM T_PRD_PORT_STORAGE_DETAIL T1 LEFT JOIN T_YARD_TALLY T2 ON T1.CARGO_TALLY_ID = T2.ID JOIN T_BUS_CARGO_INFO TBCI ON T1.CARGO_INFO_ID = TBCI.ID WHERE TBCI.CARGO_INFO_NO = #{cargoInfoNo,jdbcType=VARCHAR} AND T1.MASS_ID = #{massId,jdbcType=BIGINT}
AND T1.WORK_DATE >= #{beginWorkDate, jdbcType=TIMESTAMP}
AND ( T1.WORK_DATE > #{beginWorkDate, jdbcType=TIMESTAMP} OR T1.CLASS_CODE >= TO_NUMBER( #{beginClassCode, jdbcType=VARCHAR} ) )
AND T1.WORK_DATE <= #{endWorkDate, jdbcType=TIMESTAMP}
AND ( T1.WORK_DATE < #{endWorkDate, jdbcType=TIMESTAMP} OR T1.CLASS_CODE <= TO_NUMBER( #{endClassCode, jdbcType=VARCHAR} ) )
AND T1.PROCESS_DETAIL_CODE = #{processDetailCode, jdbcType=VARCHAR}

mapper.update:
update  M_STORAGE_STACK_POSITION set UPDATE_TIME = #{updateTime,jdbcType=TIMESTAMP},
                                     UPDATE_BY = #{updateBy}
where id  = #{id}
